-- ===========================================================================
-- Master bought-in price list v2 (May 2026)
-- Source: Master Bought In Price List.xlsx — 2,052 items derived from 1,860
-- real CCE quote files (2025-2026).
-- Adds: stock_code, last_quote_ref, last_quote_date columns + RLS-safe wipe
-- and reseed of equipment_catalogue from canonical data.
-- ===========================================================================

-- Schema additions
alter table public.equipment_catalogue
  add column if not exists stock_code text,
  add column if not exists last_quote_ref text,
  add column if not exists last_quote_date text;

create index if not exists idx_eqcat_stockcode on public.equipment_catalogue(company_id, stock_code);

-- Wipe & reseed per company
truncate public.equipment_catalogue restart identity;

do $$
declare c record;
begin
  for c in select id from public.companies loop
    -- Batch 1-100

    -- Batch 101-200

    -- Batch 201-300

    -- Batch 301-400

    -- Batch 401-500

    -- Batch 501-600

    -- Batch 601-700

    -- Batch 701-800

    -- Batch 801-900

    -- Batch 901-1000

    -- Batch 1001-1100

    -- Batch 1101-1200

    -- Batch 1201-1300

    -- Batch 1301-1400

    -- Batch 1401-1500

    -- Batch 1501-1600

    -- Batch 1601-1700

    -- Batch 1701-1800

    -- Batch 1801-1900

    -- Batch 1901-1937

  end loop;
end $$;

do $$
declare n integer;
begin
  select count(*) into n from public.equipment_catalogue;
  raise notice 'Equipment catalogue seeded: % rows total', n;
end $$;
