      (c.id, 'TFSE1-E00004', 'TFSE Products Ltd', 'SH2650', 'SH2650 Intermediate shelf 300d with LED below', 590.00, 0.00, '0725-069', 'Jul 2025'),
      (c.id, 'TFS1-E00072-AC', 'TFSE Products Ltd', 'VK1', 'Venting Kit', 290.00, 0.00, '0725-006', 'Jul 2025'),
      (c.id, 'TFSE1-E00001', 'TFSE Products td', 'DC2650R', 'Bespoke Refrigerated Display Fridge. Ventilated Cooling. 4-8C temperature, Construction 304 stainless steel. LED light Gantry, Bonded Toughened Glass screen surround. Undersection open with integral compressor and controls, together with a rear venting fan and duct system to dissipate compressor heat. Power 230v 13a R290 Gas Dimensions: 2650mm (w) x 1000mm (d) x 1300mm (h) Warranty: 2 Year Parts Only & 1 Year Labour', 6880.00, 0.00, '0725-069', 'Jul 2025'),
      (c.id, 'THE1-E00101-AC', 'Thermodyne', 'PACK B', 'Accessory Pack B for Thermodyne Unit', 770.00, 0.00, '0825-064', 'Aug 2025'),
      (c.id, 'THE1-E00103-AC', 'Thermodyne', 'PACK D', 'Accessory Pack D for Thermodyne Unit. Pack comprising: 8 x 2" stainless steel solid lid 2 x 2" stainless steel vented lid 2 x half riser 2 x full riser 8 x 1/1GN container amber 65mm deep 8 x 2/4GN container amber 65mm deep 1 x heat transfer fluid', 1356.00, 0.00, '0925-074', 'Sep 2025'),
      (c.id, 'THE1-E05000-INS', 'Thermodyne', 'Delivery', 'Delivery Standard NWH', 176.80, 0.00, '0925-074', 'Sep 2025'),
      (c.id, 'THE1-E00030', 'Thermodyne', '700CT', 'Thermodyne unit 5-shelf with doors (removable) complete with five shelves and removable doors. Max. operating temperature of 110 C. Weight: 85.7kg. Recommended Container Pack: D (not included). Dimensions: 774.7mm(w) x 628.65mm(d) x 692.15mm(h) Warranty: 1 Year Parts & Labour', 7624.00, 0.00, '0925-074', 'Sep 2025'),
      (c.id, 'THE1-E00020', 'Thermodyne', '300CT', 'Thermodyne unit counter top 5-shelf with door (removable) complete with five shelves and removable door. Max. operating temperature of 110 C. Weight: 57.2kg. Recommended Container Pack: B (not included). Dimensions: 444.5mm(w) x 628.65mm(d) x 692.15mm(h) Warranty: 1 Years Parts & Labour', 6820.00, 0.00, '0625-078', 'Jun 2025'),
      (c.id, 'THE1-E00015', 'Thermodyne', '300NDNL', 'Thermodyne unit counter top 5-shelf without door complete with five heat transfer plates. Weight: 55.8kg. Elec: Single Phase 240V 13Amp. Dimensions: 444.5mm(w) x 584.2mm(d) x 657.35mm(h) Warranty: 1 Year Parts & Labour Price is inclusive of: 4X 2” Stainless Steel Solid Lid 1X 2” Stainless Steel Vented Lid 1X Half Riser 1X Full Riser 1X Heat Transfer Fluid 4X 1/1X65A 6X 2/4X65A', 6451.50, 0.00, '0825-064', 'Aug 2025'),
      (c.id, 'TMX1-E0004', 'Thermomix', 'TM7', 'Countertop TM7 Thermomix Unit comes complete with the following: Varoma® set, Lid cap, Mixing bowl lid, Simmering basket, Mixing knife, TM7 mixing bowl, Knife locking lever, Thermomix® base, Spatula, Butterfly whisk, 10” multi-touch display, Maintenance-free Vorwerk synchronous motor Hardware Highlights Sleek and modern flat design, Large 10” multi-touch display for better cooking experience, Vorwerk motor with an extensive rpm range, delivering quiet and efficient performance for delicate and hard ingredients. Insulated stainless steel bowl meeting EU safety regulations. Knife locking lever for easy (re)assemble of mixing bowl. Slider foot for easy base manoeuvrability. Modern rectangular design of ?Varoma® for optimised space and a multifaceted, versatile, and efficient spatula with broa', 1124.17, 0.00, '0426-062', 'Apr 2026'),
      (c.id, 'HAR1-00303', 'TP Extrusions', 'TP02 B026', 'Plastic H Section (silver)', 25.00, 0.00, '0426-016', 'Apr 2026'),
      (c.id, 'TRU1-E0008', 'TRUE', 'TUC-24F-HC', 'Freezer Undercounter Solid Door with Hydrocarbon refrigerant. Factory engineered self-contained capillary tube system using environmentally friendly R290 hydro carbon refrigerant that has zero (0) ozone depletion potential (ODP) & three (3) global warming potential (GWP). All stainless steel front top and ends. Matching aluminum finished back. Interior - attractive NSF approved clear coated aluminum liner. Stainless steel floor with coved corners. Heavy duty PVC coated gray wire shelves. Automatic defrost system timeinitiated time-terminated. Foamed-in-place using a high density polyurethane insulation that has zero ozone depletion potential (ODP) and zero global warming potential (GWP). Dimensions: 610mm(w) x 629mm(d) x 802mm Warranty - 7 year parts and labour', 2728.00, 59.50, '0426-057', 'Apr 2026'),
      (c.id, 'TRU1-E02939', 'True', 'TDR60-RISZ1-R-B-SS-1', 'ITEM OMITTED: True Bespoke Draft Fridge Temperatures of 33°F to 38°F (.5°C to 3.3°C), Exterior: Black powder coated cold rolled steel with stainless steel countertop, Interior: Stainless steel, RCU Technology, White LED interior lighting, NSF/ANSI standard 7 compliant for the storage and/or display of packaged or bottled product, UL Rated for outdoor use, Three (3) interior access ports, Field reversible doors, Zero clearance (side and back), Front air intake / front air discharge, Electronic temperature control with exterior digital display15" (381mm) surface mounted drip tray trough 3" (77mm) diameter insulated column with single faucet and 2-way manifold Dimensions: 1524mm(w) x 631mm(d) x 881mm(h) Warranty: 5 Years Parts & Labour', 3237.57, 0.00, '0325-054', 'Mar 2025'),
